SmartRisk.Card={panel({title,badge="",body=""}){return `<article class="panel"><header class="panel-header"><h2 class="section-title">${title}</h2>${badge?`<span class="badge">${badge}</span>`:""}</header><div class="panel-body">${body}</div></article>`},metric(m){return `<article class="metric-card"><div class="metric-top"><span class="metric-icon">${SmartRisk.Icon.render(m.icon,21)}</span><span class="trend-positive">${m.trend}</span></div><div class="metric-label">${m.label}</div><div class="metric-value">${m.value}</div><p class="metric-note">${m.note}</p></article>`}};